function App(){const[route,setRoute]=useState(location.pathname+location.search),[data,setData]=useState(()=>safeLoad('dineflow_data',seed())),[session,setSession]=useState(()=>safeLoad('dineflow_session',null)),[remote,setRemote]=useState('checking'),[toast,setToast]=useState('');const show=m=>{setToast(m);setTimeout(()=>setToast(''),2500)},nav=p=>{history.pushState({},'',p);setRoute(location.pathname+location.search);scrollTo(0,0)};useEffect(()=>{let f=()=>setRoute(location.pathname+location.search);addEventListener('popstate',f);return()=>removeEventListener('popstate',f)},[]);useEffect(()=>{safeStore('dineflow_data',data);safeStore('dineflow_local_backup',{savedAt:now(),data})},[data]);useEffect(()=>{try{session?safeStore('dineflow_session',session):localStorage.removeItem('dineflow_session')}catch(e){}},[session]);useEffect(()=>{(async()=>{try{let{data:rows,error}=await db.from(T).select('*').order('created_at');if(error)throw error;let out=empty();(rows||[]).forEach(row=>{let k=REV[row.record_type];if(k)out[k].push(row.data)});setRemote('online');if(Object.values(out).some(a=>a.length))setData(out)}catch(e){setRemote('local');console.warn('Supabase fallback:',e.message)}})()},[]);const commit=n=>setData(clone(n)),upsert=async(k,item)=>{let n=clone(data),a=n[k],i=a.findIndex(x=>x.id===item.id);i>-1?a[i]=item:a.unshift(item);commit(n);if(remote==='online'){let{error}=await db.from(T).upsert({id:item.id,record_type:TYPE[k],restaurant_id:item.restaurantId||item.id,data:item,updated_at:now()});if(error){console.error('Supabase save error',error);setRemote('local');show('Save issue: '+error.message)}else if(['orders','printJobs','restaurants'].includes(k)){localStorage.dineflow_last_cloud_sync=now();show('Synced to Cloud')}}},remove=async(k,id)=>{let n=clone(data);n[k]=(n[k]||[]).filter(x=>x.id!==id);commit(n);if(remote==='online')await db.from(T).delete().eq('id',id)},bulk=async ops=>{let n=clone(data);ops.forEach(({key,item})=>{let a=n[key],i=a.findIndex(x=>x.id===item.id);i>-1?a[i]=item:a.unshift(item)});commit(n);if(remote==='online'){for(let o of ops)await db.from(T).upsert({id:o.item.id,record_type:TYPE[o.key],restaurant_id:o.item.restaurantId||o.item.id,data:o.item,updated_at:now()});localStorage.dineflow_last_cloud_sync=now();show('Cloud Saved Successfully')}};const common={data,session,setSession,nav,show,upsert,bulk,remove,remote};let p=route.split('?')[0];return <>{p.startsWith('/booking/')?<GuestBooking {...common} slug={p.split('/')[2]}/>:p.startsWith('/menu/')?<GuestMenu {...common} slug={p.split('/')[2]}/>:p==='/login'?<Login {...common}/>:p==='/super-admin'?(session?.role==='super_admin'?<SuperAdmin {...common} logout={()=>{setSession(null);nav('/')}}/>:<Login {...common}/>):p==='/app'?(['owner','staff'].includes(session?.role)?<OwnerApp {...common} logout={()=>{setSession(null);nav('/')}}/>:<Login {...common}/>):<Landing nav={nav} remote={remote} data={data}/>} {toast&&<div className="toast">{toast}</div>}</>}
